      ctx.lineTo(cx, b3CY + b3HD);
      ctx.lineTo(cx - b3HW, b3CY);
      ctx.closePath();
      ctx.fill();
      ctx.fillStyle = sandMid;
      ctx.beginPath();
      ctx.moveTo(cx - b3HW, b3CY);
      ctx.lineTo(cx, b3CY + b3HD);
      ctx.lineTo(cx, b3CY + b3HD + b3WH);
      ctx.lineTo(cx - b3HW, b3CY + b3WH);
