      ctx.beginPath();
      ctx.arc(screenPos.x - 8 * s, glyphY + 1 * s, 1.5 * s, 0, Math.PI * 2);
      ctx.stroke();
      ctx.beginPath();
      ctx.moveTo(screenPos.x - 8 * s, glyphY + 3.5 * s);
      ctx.quadraticCurveTo(
        screenPos.x - 10 * s,
        glyphY + 6 * s,
        screenPos.x - 12 * s,
        glyphY + 5 * s,
      );
