        // === CRACKS ===
        ctx.strokeStyle = "#2a2a1a";
        ctx.lineWidth = 0.7 * s;
        ctx.beginPath();
        ctx.moveTo(wX + 12 * s, wTopY + 8 * s);
        ctx.lineTo(wX + 14 * s, screenPos.y - 16 * s);
        ctx.lineTo(wX + 12 * s, screenPos.y - 8 * s);
