        ctx.moveTo(lpX - lpR - 2 * s, screenPos.y - lpH + 4 * s);
        ctx.lineTo(lpX + lpR + 6 * s, screenPos.y - lpH + 2 * s);
        ctx.lineTo(lpX + lpR + 4 * s, screenPos.y - lpH);
        ctx.lineTo(lpX - lpR - 4 * s, screenPos.y - lpH + 2 * s);
