        ctx.fill();
        ctx.fillStyle = stoneLight;
        ctx.beginPath();
        ctx.moveTo(w2X, w2TopY + 4 * s);
        ctx.lineTo(w2X + 5 * s, w2TopY);
        ctx.lineTo(w2X + 12 * s, w2TopY + 6 * s);
        ctx.lineTo(w2X + w2W, w2TopY + 3 * s);
        ctx.lineTo(w2X + w2W + w2Th, w2TopY + 6 * s);
