        torsoG.addColorStop(0, figureLight);
        torsoG.addColorStop(0.5, figureMid);
        torsoG.addColorStop(1, figureDark);
        ctx.fillStyle = torsoG;
        ctx.beginPath();
        ctx.moveTo(fx + 3 * s, tB - 10 * s);
        ctx.bezierCurveTo(
          fx,
          tB - 14 * s,
          fx - 4 * s,
          tB - 16 * s,
          fx - 7 * s,
          tB - 13 * s,
        );
        ctx.lineTo(fx - 6 * s, tB - 5 * s);
        ctx.bezierCurveTo(
          fx - 2 * s,
          tB - 6 * s,
          fx + 2 * s,
          tB - 5 * s,
          fx + 4 * s,
          tB - 5 * s,
        );
        ctx.closePath();
        ctx.fill();
        // Spine highlight
        ctx.strokeStyle = "rgba(200,195,185,0.12)";
        ctx.lineWidth = 1 * s;
        ctx.beginPath();
        ctx.moveTo(fx + 2 * s, tB - 10 * s);
        ctx.bezierCurveTo(
          fx - 1 * s,
          tB - 13 * s,
          fx - 4 * s,
          tB - 15 * s,
          fx - 7 * s,
          tB - 14 * s,
        );
