        // Shoulder muscle
        ctx.fillStyle = "rgba(200,195,185,0.12)";
        ctx.beginPath();
        ctx.ellipse(
          fx - 8 * s,
          tB - 15 * s,
          3 * s,
          2.5 * s,
          -0.3,
          0,
          Math.PI * 2,
        );
