          ctx.beginPath();
          ctx.moveTo(tHX + (ex + edir * 0.5) * s, tHY - 4.5 * s);
          ctx.lineTo(tHX + (ex + edir * 2) * s, tHY - 7 * s);
          ctx.lineTo(tHX + (ex + edir * 3) * s, tHY - 5.2 * s);
          ctx.closePath();
