        ctx.bezierCurveTo(
          fx - 9 * s,
          hY - 19 * s,
          fx - 10 * s,
          hY - 23 * s,
          fx - 9 * s,
          hY - 27 * s,
        );
        ctx.closePath();
        ctx.fill();
