        ctx.strokeStyle = figureDark;
        ctx.lineWidth = 0.5 * s;
        ctx.beginPath();
        ctx.moveTo(fx - 4 * s, cTB - 15.5 * s);
        ctx.lineTo(fx + 1 * s, cTB - 7.5 * s);
